<?php require 'auth.php'; require_login(); $d=content(); if($_POST){ if(!empty($_FILES['image']['name'])){ $name=preg_replace('/[^a-zA-Z0-9._-]/','_',basename($_FILES['image']['name'])); move_uploaded_file($_FILES['image']['tmp_name'], dirname(__DIR__).'/assets/images/'.$name); $d['gallery'][]=$name; } if(isset($_POST['delete'])){ $d['gallery']=array_values(array_filter($d['gallery'], fn($x)=>$x!==$_POST['delete'])); } save_content($d); $msg='Gallery updated'; } ?>
<!doctype html><html><head><title>Edit Gallery</title><link rel="stylesheet" href="../assets/css/style.css"><style>.wrap{max-width:900px;margin:30px auto}.imgs{display:grid;grid-template-columns:repeat(auto-fit,minmax(180px,1fr));gap:15px}.imgs img{width:100%;height:140px;object-fit:cover;border-radius:8px}.card{background:#fff;padding:12px}</style></head><body><div class="wrap"><h1>Gallery</h1><?php if(!empty($msg)) echo '<p style="color:green">'.$msg.'</p>'; ?><form method="post" enctype="multipart/form-data"><input type="file" name="image" accept="image/*" required> <button class="btn">Upload Image</button></form><div class="imgs"><?php foreach($d['gallery'] as $img): ?><div class="card"><img src="../assets/images/<?=e($img)?>"><form method="post"><button name="delete" value="<?=e($img)?>">Delete</button></form></div><?php endforeach; ?></div><p><a href="index.php">Back</a></p></div></body></html>
